import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Email Integration","description":"","frontmatter":{},"headers":[],"relativePath":"settings/email.md","filePath":"settings/email.md"}'),l={name:"settings/email.md"};function r(n,e,s,m,d,u){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="email-integration" tabindex="-1">Email Integration <a class="header-anchor" href="#email-integration" aria-label="Permalink to &quot;Email Integration&quot;">​</a></h1><p>Configure how MyCompanyDesk sends emails to your customers — from invoice delivery to payment reminders.</p><h2 id="email-delivery-methods" tabindex="-1">Email delivery methods <a class="header-anchor" href="#email-delivery-methods" aria-label="Permalink to &quot;Email delivery methods&quot;">​</a></h2><p>MyCompanyDesk supports three ways to send emails:</p><h3 id="_1-built-in-email-default" tabindex="-1">1. Built-in email (default) <a class="header-anchor" href="#_1-built-in-email-default" aria-label="Permalink to &quot;1. Built-in email (default)&quot;">​</a></h3><p>Out of the box, emails are sent through MyCompanyDesk&#39;s own email service. No configuration needed.</p><h3 id="_2-gmail-integration" tabindex="-1">2. Gmail integration <a class="header-anchor" href="#_2-gmail-integration" aria-label="Permalink to &quot;2. Gmail integration&quot;">​</a></h3><p>Send emails directly from your Gmail account:</p><ol><li>Go to <strong>Settings &gt; Communication &gt; Email</strong></li><li>Click <strong>Connect Gmail</strong></li><li>Authorize MyCompanyDesk to send on your behalf via Google OAuth</li><li>Emails now appear as sent from your Gmail address</li></ol><p><strong>Benefits:</strong></p><ul><li>Emails show your Gmail address as the sender</li><li>Sent emails appear in your Gmail Sent folder</li><li>Better deliverability (your own domain reputation)</li></ul><h3 id="_3-outlook-microsoft-integration" tabindex="-1">3. Outlook / Microsoft integration <a class="header-anchor" href="#_3-outlook-microsoft-integration" aria-label="Permalink to &quot;3. Outlook / Microsoft integration&quot;">​</a></h3><p>Send from your Outlook or Microsoft 365 account:</p><ol><li>Go to <strong>Settings &gt; Communication &gt; Email</strong></li><li>Click <strong>Connect Outlook</strong></li><li>Authorize via Microsoft OAuth</li><li>Emails are sent from your Outlook address</li></ol><h3 id="_4-custom-smtp" tabindex="-1">4. Custom SMTP <a class="header-anchor" href="#_4-custom-smtp" aria-label="Permalink to &quot;4. Custom SMTP&quot;">​</a></h3><p>For full control, use your own SMTP server:</p><ol><li>Go to <strong>Settings &gt; Communication &gt; Email</strong></li><li>Enter your SMTP details: <ul><li><strong>Host</strong> — SMTP server address</li><li><strong>Port</strong> — Server port (587 for TLS, 465 for SSL)</li><li><strong>Username</strong> — SMTP login</li><li><strong>Password</strong> — SMTP password</li></ul></li><li>Click <strong>Test Connection</strong> to verify it works</li><li>Save</li></ol><h2 id="email-templates" tabindex="-1">Email templates <a class="header-anchor" href="#email-templates" aria-label="Permalink to &quot;Email templates&quot;">​</a></h2><p>Customize the emails sent with your invoices and reminders.</p><h3 id="invoice-email-template" tabindex="-1">Invoice email template <a class="header-anchor" href="#invoice-email-template" aria-label="Permalink to &quot;Invoice email template&quot;">​</a></h3><p>The default email sent when delivering an invoice. Customize:</p><ul><li><strong>Subject line</strong> — The email subject (supports variables like invoice number)</li><li><strong>Body</strong> — The message content</li><li><strong>Language</strong> — Set per-language templates</li></ul><h3 id="reminder-email-template" tabindex="-1">Reminder email template <a class="header-anchor" href="#reminder-email-template" aria-label="Permalink to &quot;Reminder email template&quot;">​</a></h3><p>The email sent when following up on overdue invoices. Customize the same fields as above but with a more urgent tone.</p><h3 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h3><p>Before sending, you can preview any email to see exactly what your customer will receive:</p><ul><li>Rendered HTML with your branding</li><li>PDF attachment preview</li><li>Payment link inclusion</li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><p>Email templates support dynamic variables:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>{invoice_number}</code></td><td>The invoice number</td></tr><tr><td><code>{customer_name}</code></td><td>Customer&#39;s name</td></tr><tr><td><code>{amount}</code></td><td>Total invoice amount</td></tr><tr><td><code>{due_date}</code></td><td>Payment due date</td></tr><tr><td><code>{company_name}</code></td><td>Your company name</td></tr><tr><td><code>{payment_link}</code></td><td>Link to online payment</td></tr></tbody></table><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>Configure what email notifications you receive:</p><ul><li><strong>Invoice paid</strong> — Get notified when a customer pays</li><li><strong>Quote request received</strong> — Alert for new quote requests</li><li><strong>Team activity</strong> — Updates on team member actions</li></ul><p>Notification preferences can be set in your <a href="/account/profile">Profile</a>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Connect Gmail or Outlook for the best deliverability</li><li>Always test your email template before sending your first invoice</li><li>Set up language-specific templates if you serve customers in multiple languages</li><li>Use the reminder template for professional follow-ups on overdue invoices</li></ul>',36)])])}const p=t(l,[["render",r]]);export{h as __pageData,p as default};
